    "grammar": [
      {
        "formula": "Allô, bonjour + présentation",
        "use": "Apertura formal de una llamada telefónica: primero se saluda y luego se dice quién eres o qué quieres. « Allô, bonjour. Cabinet médical, j'écoute. » Nunca se abre con « Salut » a un desconocido o a un servicio."
      },
      {
        "formula": "Je vous appelle pour + nom / infinitif",
        "use": "Para dar el motivo de la llamada con el « vous » formal: « Je vous appelle pour un rendez-vous. » / « Je vous appelle pour confirmer mon rendez-vous. » Con amigos se diría « je t'appelle », pero con servicios siempre « je vous appelle »."
      },
      {
        "formula": "Pouvez-vous + infinitif, s'il vous plaît ?",
        "use": "Petición cortés con « vous », muy frecuente por teléfono: « Pouvez-vous répéter, s'il vous plaît ? » / « Pouvez-vous parler plus lentement ? » La forma informal « tu peux… ? » no se usa con desconocidos."
      },
      {
        "formula": "Je vous remercie. + Bonne journée, au revoir !",
        "use": "Cierre formal de la llamada: se agradece y se despide con « vous ». « Je vous remercie. Bonne journée, au revoir ! » La recepcionista puede cerrar con « Merci d'avoir appelé »."
      }
    ],
