    "grammar": [
      {
        "formula": "sujet + le/la/les + verbe conjugué",
        "use": "El pronombre COD va SIEMPRE antes del verbo conjugado, nunca después: « Je rappelle Paul → Je le rappelle. » Error típico: « je rappelle le »."
      },
      {
        "formula": "je le + verbe (masculin singulier)",
        "use": "« le » reemplaza un objeto directo masculino singular ya mencionado: « Tu as le numéro ? — Oui, je le note. »"
      },
      {
        "formula": "je la + verbe (féminin singulier)",
        "use": "« la » reemplaza un objeto directo femenino singular: « Je rappelle Marie → Je la rappelle. »"
      },
      {
        "formula": "je les + verbe (pluriel) / le, la → l' + voyelle",
        "use": "« les » reemplaza un plural: « J'écoute les messages → Je les écoute. » Ante vocal, le/la se convierten en l': « Je l'écoute »."
      }
    ],
