      {
        "formula": "je + verbe + aujourd'hui / ce soir",
        "use": "Sitúa la acción en el día de hoy: « Je rappelle ce soir. » / « Je ne peux pas aujourd'hui. » Ojo con el error típico: « ce soir » = esta noche (hoy), « demain » = mañana. ¡No son lo mismo!"
      },
      {
        "formula": "demain + matin / soir",
        "use": "Sitúa la acción en el día siguiente y precisa el momento: « Je te réponds demain matin. » / « On peut faire ça demain. »"
      },
      {
        "formula": "tout de suite / plus tard / bientôt",
        "use": "Ordenan las acciones sin dar una hora exacta: « tout de suite » = ahora mismo, « plus tard » = más tarde, « bientôt » = pronto. Ejemplo: « Je ne suis pas joignable, je rappelle plus tard. »"
      },
      {
        "formula": "C'est pour + aujourd'hui / demain",
        "use": "Sirve para preguntar o confirmar cuándo pasa algo: « C'est pour aujourd'hui ? — Non, c'est pour demain. » Muy útil para verificar un mensaje de voz."
      }
