      {
        "formula": "plus + adjectif + que",
        "use": "Para decir «más… que». « Cet appartement est plus grand que l'autre. » ¡Ojo! No olvides nunca « que » después del adjetivo. Pronunciación: plus [ply]."
      },
      {
        "formula": "moins + adjectif + que",
        "use": "Para decir «menos… que». Con « cher » equivale a «más barato que»: « Ce studio est moins cher que l'appartement. » Pronunciación: moins [mwɛ̃]."
      },
      {
        "formula": "aussi + adjectif + que",
        "use": "Para decir «tan… como». En francés se usa « que », NO « comme »: « C'est aussi lumineux que l'autre appartement. » Pronunciación: aussi [osi]."
      },
      {
        "formula": "le / la plus (moins) + adjectif + de",
        "use": "El superlativo: «el más / el menos». « C'est le plus grand appartement du quartier. » « Ce studio est le moins cher. » Sirve para justificar tu elección final."
      }
