    "grammar": [
      {
        "formula": "lui + verbe",
        "use": "« Lui » reemplaza « à + una persona » (singular, hombre o mujer) y va ANTES del verbo: « Je parle au conseiller → Je lui parle. » / « J'écris à Marie → Je lui écris. »"
      },
      {
        "formula": "leur + verbe",
        "use": "« Leur » reemplaza « à + varias personas » y también va antes del verbo: « J'écris aux voisins → Je leur écris. » / « Je téléphone à mes parents → Je leur téléphone. »"
      },
      {
        "formula": "ne + lui/leur + verbe + pas",
        "use": "En la negación, el pronombre queda entre « ne » y el verbo: « Je ne lui donne pas mon code PIN. » / « Je ne leur réponds pas tout de suite. »"
      },
      {
        "formula": "lui/leur (COI) ≠ le/la (COD)",
        "use": "Con verbos que llevan « à » (parler à, dire à, écrire à, demander à, donner à) usa lui/leur, no le/la: « Je lui dis bonjour » (correcto), « je le dis bonjour » (error)."
      }
    ],
