    "grammar": [
      {
        "formula": "venir de + infinitif",
        "use": "El passé récent: expresa que algo ACABA de pasar. Es la forma más natural en francés para acciones muy recientes. « Je viens d'envoyer le colis. » = Acabo de enviar el paquete."
      },
      {
        "formula": "je viens / tu viens / il vient de + infinitif",
        "use": "En singular solo se conjuga « venir » en presente; el otro verbo queda en infinitivo. « Il vient de partir. » = Él acaba de irse. Pronunciación: je viens de [ʒəvjɛ̃də]."
      },
      {
        "formula": "nous venons / vous venez / ils viennent de + infinitif",
        "use": "En plural funciona igual: cambia « venir », el infinitivo no se toca. « Nous venons de peser le paquet. » = Acabamos de pesar el paquete."
      },
      {
        "formula": "venir d' + infinitif (ante vocal)",
        "use": "Ante vocal o h muda, « de » se convierte en « d' »: « Elle vient d'acheter un timbre. » Ojo: para lo muy reciente evita el passé composé; « je viens d'envoyer » suena más inmediato que « j'ai envoyé »."
      }
    ],
